.querySelector('svg');    btn.disabled = true;    fetch("{{ route('user.wishlists.toggle') }}", {        method: "POST",        headers: {            "X-CSRF-TOKEN": csrfToken,            "Content-Type": "application/json",            "Accept": "application/json"        },        body: JSON.stringify({ product_id: productId })    })    .then(res => res.json())    .then(data => {        if (data.status === 'added') {            svg.setAttribute('fill', 'currentColor');            btn.classList.remove('text-white', 'hover:bg-red-600/80');            btn.classList.add('text-red-500', 'bg-red-600/80');        } else {            svg.setAttribute('fill', 'none');            btn.classList.remove('text-red-500', 'bg-red-600/80');            btn.classList.add('text-white', 'hover:bg-red-600/80');        }    })    .catch(() => {})    .finally(() => { btn.disabled = false; });}</script>@endsection